const response = $input.first().json;
const results = response.local_results || response.place_results || [];

const leads = results.map(r => {
  const name = r.title || r.name || '';
  const address = r.address || '';
  const phone = r.phone || '';
  const website = r.website || '';
  const city = (address.split(',')[1] || '').trim();
  const state = (address.split(',')[2] || '').trim().split(' ')[0] || '';

  // Extract domain from website URL
  let domain = '';
  if (website) {
    try {
      domain = new URL(website.startsWith('http') ? website : 'https://' + website).hostname.replace('www.', '');
    } catch (e) {
      domain = website.replace(/^https?:\/\//, '').replace(/^www\./, '').split('/')[0];
    }
  }

  return {
    json: {
      business_name: name,
      address,
      phone,
      website,
      domain,
      city,
      state,
      source: 'google_maps'
    }
  };
}).filter(l => l.json.domain);

if (leads.length === 0) {
  return [{ json: { _empty: true, reason: 'No leads with websites found' } }];
}

return leads;

const hunterResponse = $input.first().json;
const leadData = $('Extract Lead Data').first().json;

// Get best email from Hunter response
const data = hunterResponse.data || {};
const emails = data.emails || [];

let bestEmail = '';
let firstName = '';
let lastName = '';

if (emails.length > 0) {
  // Prefer emails with high confidence, owner/manager type
  const sorted = emails.sort((a, b) => (b.confidence || 0) - (a.confidence || 0));
  const best = sorted[0];
  bestEmail = best.value || '';
  firstName = best.first_name || '';
  lastName = best.last_name || '';
}

if (!bestEmail) {
  return [{ json: { _skip: true, reason: 'No email found', business_name: leadData.business_name } }];
}

return [{
  json: {
    business_name: leadData.business_name,
    email: bestEmail,
    first_name: firstName,
    last_name: lastName,
    phone: leadData.phone,
    website: leadData.website,
    city: leadData.city,
    state: leadData.state,
    source: leadData.source
  }
}];

const verifyResponse = $input.first().json;
const leadData = $('Extract Best Email').first().json;

// MillionVerifier returns { result: 'ok' | 'catch_all' | 'invalid' | 'disposable' | 'unknown', ... }
const result = (verifyResponse.result || '').toLowerCase();
const quality = (verifyResponse.quality || '').toLowerCase();

// Accept 'ok' and 'catch_all', reject everything else
const acceptable = ['ok', 'catch_all'];

if (!acceptable.includes(result)) {
  return [{
    json: {
      _skip: true,
      reason: 'Email validation failed: ' + result,
      email: leadData.email,
      business_name: leadData.business_name
    }
  }];
}

return [{
  json: {
    ...leadData,
    email_verified: true,
    email_verify_result: result
  }
}];

const dupeCheck = $input.first().json;
const leadData = $('DNC Check (Placeholder)').first().json;

// If Supabase returned an array with results, it's a duplicate
const results = Array.isArray(dupeCheck) ? dupeCheck : [];

if (results.length > 0) {
  return [{ json: { _skip: true, reason: 'Duplicate lead', email: leadData.email } }];
}

return [{ json: { ...leadData, _skip: false } }];

const leads = $input.all().map(i => i.json);
const allLeads = Array.isArray(leads[0]) ? leads[0] : leads;
const now = new Date();
const results = [];

for (const lead of allLeads) {
  if (!lead.email || !lead.status) continue;

  const lastContacted = lead.last_contacted_at ? new Date(lead.last_contacted_at) : null;
  const daysSinceContact = lastContacted ? Math.floor((now - lastContacted) / (1000 * 60 * 60 * 24)) : 999;

  let emailType = null;
  let newStatus = null;

  if (lead.status === 'new') {
    emailType = 'initial';
    newStatus = 'contacted';
  } else if (lead.status === 'follow_up_1' && daysSinceContact >= 3) {
    emailType = 'follow_up_1';
    newStatus = 'follow_up_2';
  } else if (lead.status === 'follow_up_2' && daysSinceContact >= 7) {
    emailType = 'follow_up_2';
    newStatus = 'completed';
  }

  if (emailType) {
    results.push({
      json: {
        id: lead.id,
        business_name: lead.business_name,
        email: lead.email,
        first_name: lead.first_name || '',
        city: lead.city || '',
        state: lead.state || '',
        status: lead.status,
        emailType,
        newStatus
      }
    });
  }
}

if (results.length === 0) {
  return [{ json: { _skip: true, reason: 'No leads ready for email today' } }];
}

// Enforce 30/day rate limit
return results.slice(0, 30);

/*
 * ============================================================
 * ANTI-AI-DETECTION RULES (MANDATORY FOR ALL EMAIL TEMPLATES)
 * ============================================================
 * - NEVER use: delve, leverage, utilize, harness, elevate, empower,
 *   streamline, robust, seamless, cutting-edge, game-changer,
 *   innovative, revolutionize, best-in-class, holistic, synergy, paradigm
 * - NEVER use em dashes (use commas, periods, or "--" instead)
 * - ALWAYS use contractions (I'm, can't, won't, you're, we're)
 * - Vary sentence length dramatically (some 3 words, some 30 words)
 * - Include 1-2 casual imperfections per email (sentence fragments,
 *   starting with "And" or "But")
 * - Reference specific numbers, names, and details
 * - Sound like a real founder typing quickly, not a marketing team
 * - Keep paragraphs short (1-3 sentences)
 * - Have opinions. Take positions. Don't hedge everything.
 * - Write at an 8th grade reading level
 * ============================================================
 */
const lead = $input.first().json;
const { business_name, first_name, last_name, city, emailType, title, seniority, company_size, annual_revenue, linkedin_url, technologies } = lead;
const name = first_name || 'there';
const fullName = [first_name, last_name].filter(Boolean).join(' ') || 'there';

// ── Build Apollo-enriched personalization snippets ──
let titleLine = '';
if (title) {
  titleLine = `as the ${title.toLowerCase()} at`;
} else {
  titleLine = 'at';
}

let teamSizeLine = '';
if (company_size) {
  const size = parseInt(company_size);
  if (size && size > 0) {
    if (size <= 5) teamSizeLine = 'With a small crew';
    else if (size <= 15) teamSizeLine = `With a team of ${size} techs`;
    else if (size <= 30) teamSizeLine = `With ${size} people on your team`;
    else teamSizeLine = `Running a ${size}-person operation`;
  }
}

let techStackLine = '';
if (technologies && Array.isArray(technologies) && technologies.length > 0) {
  const techNames = technologies.slice(0, 3).map(t => typeof t === 'string' ? t : (t.name || '')).filter(Boolean);
  if (techNames.length > 0) {
    techStackLine = `I noticed you're using ${techNames.join(', ')}. `;
  }
}

let linkedinCta = '';
if (linkedin_url) {
  linkedinCta = `\n\nP.S. Happy to connect on LinkedIn too: ${linkedin_url}`;
}

let revenueLine = '';
if (annual_revenue) {
  // Don't mention revenue directly - too personal. But use it to gauge messaging.
  // High revenue shops get the ROI angle, smaller shops get the simplicity angle.
}

// ── Fetch learning data from the 3 intelligence queries ──
let perfData = [];
let subjectLineData = [];
let recentLearnings = [];

try {
  const perfRaw = $('Fetch Outreach Performance').all().map(i => i.json);
  perfData = Array.isArray(perfRaw[0]) ? perfRaw[0] : (Array.isArray(perfRaw) ? perfRaw : []);
  perfData = perfData.filter(r => r && r.tone && !r.error);
} catch (e) { perfData = []; }

try {
  const subjRaw = $('Fetch Best Subject Lines').all().map(i => i.json);
  subjectLineData = Array.isArray(subjRaw[0]) ? subjRaw[0] : (Array.isArray(subjRaw) ? subjRaw : []);
  subjectLineData = subjectLineData.filter(r => r && r.subject_line && !r.error);
} catch (e) { subjectLineData = []; }

try {
  const learnRaw = $('Fetch Recent Learnings').all().map(i => i.json);
  recentLearnings = Array.isArray(learnRaw[0]) ? learnRaw[0] : (Array.isArray(learnRaw) ? learnRaw : []);
  recentLearnings = recentLearnings.filter(r => r && r.tone && !r.error);
} catch (e) { recentLearnings = []; }

const signature = 'Best,\nShalin\nFounder, BayFlow\nshalin@bayflow.com';

const canSpamFooter = '\n\nBayFlow | 8 The Green, Ste R, Dover, DE 19901 | bayflow.com\n\nDon\'t want to hear from us? Reply \'unsubscribe\' and we\'ll remove you immediately.';

// ── Template Variants (Apollo-enriched) ──
const initialVariants = [
  {
    id: 'A',
    tone: 'pain_point',
    angle: 'problem_aware',
    hook_type: 'question',
    subject: (biz) => `Quick question about ${biz}`,
    body: (n, biz, c) => `Hey ${n},${title ? ' ' + titleLine + ' ' + biz : ''}\n\n${teamSizeLine ? teamSizeLine + ', keeping track of repair orders on paper or spreadsheets gets old fast.' : 'I noticed ' + biz + ' is running repairs in ' + c + '. Are you still using paper tickets or a generic system to track repair orders?'}\n\n${techStackLine}We built BayFlow specifically for independent auto repair shops. It handles scheduling, digital inspections (with photos your customers can see), invoicing, and customer management. Shops using it say they save about 5 hours a week on paperwork.\n\nIt's $49/month and you can try it free for 14 days. No credit card needed.\n\nWorth a look? Here's a 2-minute demo: https://bayflow.com/demo${linkedinCta}\n\n${signature}${canSpamFooter}`
  },
  {
    id: 'B',
    tone: 'social_proof',
    angle: 'outcome_focused',
    hook_type: 'statistic',
    subject: (biz) => `${biz} + 5 hours back per week`,
    body: (n, biz, c) => `Hi ${n},\n\nShops using BayFlow save an average of 5 hours per week on admin work. That's a full half-day back to focus on cars, not paperwork.\n\n${teamSizeLine ? teamSizeLine + ', that adds up fast.' : ''} We're a shop management platform built specifically for independent repair shops like ${biz}. Digital inspections with photos, one-click invoicing, and a scheduling board your techs will actually use.\n\n${techStackLine}$49/month, 14-day free trial, no credit card: https://bayflow.com${linkedinCta}\n\n${signature}${canSpamFooter}`
  },
  {
    id: 'C',
    tone: 'curiosity',
    angle: 'competitor_comparison',
    hook_type: 'competitor_weakness',
    subject: (biz) => `Saw ${biz} online, had a thought`,
    body: (n, biz, c) => `Hi ${n},\n\nI was looking at auto repair shops in ${c} and came across ${biz}. ${title ? 'As the ' + title.toLowerCase() + ', you probably know this already - ' : 'Quick question: '}are you happy with your current shop management setup?\n\n${techStackLine}Most shops we talk to are either on expensive legacy systems (Mitchell 1, Tekmetric) or duct-taping spreadsheets together. We built BayFlow as the modern alternative: simple, mobile-friendly, and $49/month flat.\n\nDigital inspections, scheduling, invoicing, customer texting, all in one place.\n\nHere's a quick look: https://bayflow.com/demo${linkedinCta}\n\n${signature}${canSpamFooter}`
  },
  {
    id: 'D',
    tone: 'friendly',
    angle: 'compliment_first',
    hook_type: 'compliment',
    subject: (biz) => `Nice reviews, ${biz}!`,
    body: (n, biz, c) => `Hi ${n},\n\nI came across ${biz} while researching shops in ${c}, and your customer reviews are impressive. ${teamSizeLine ? teamSizeLine + ', that\'s no small feat.' : 'It\'s clear your team does great work.'}\n\nI'm curious, are you using any software to manage your repair orders and customer communication? We built BayFlow for shops like yours: digital inspections with photos (customers love these), easy invoicing, and a scheduling board.\n\n$49/month, 14-day free trial: https://bayflow.com${linkedinCta}\n\n${signature}${canSpamFooter}`
  },
  {
    id: 'E',
    tone: 'urgent',
    angle: 'roi_focused',
    hook_type: 'roi',
    subject: (biz) => `$49/month that pays for itself in week 1`,
    body: (n, biz, c) => `Hi ${n},\n\nQuick math for ${biz}: shops using BayFlow's digital inspection feature see an 89% approval rate on recommended services. ${teamSizeLine ? teamSizeLine + ', that means significantly more approved repairs per car, every single day.' : 'That means more approved repairs per car, every single day.'}\n\nAt $49/month, most shops tell us it pays for itself by the end of week one.\n\n${techStackLine}Scheduling, inspections, invoicing, customer texting. Built for independent shops, not enterprise dealerships.\n\n14-day free trial, no credit card: https://bayflow.com${linkedinCta}\n\n${signature}${canSpamFooter}`
  }
];

const followUp1Variants = [
  {
    id: 'A',
    tone: 'pain_point',
    angle: 'feature_highlight',
    hook_type: 'question',
    subject: (biz) => `Re: Quick question about ${biz}`,
    body: (n, biz, c) => `Hey ${n},\n\nJust bumping this up. Wanted to make sure you saw it.\n\nBayFlow's digital inspection feature alone is worth checking out. Your techs snap photos of worn parts, customer gets a text with the photos, and they approve the work right from their phone. Shops see 89% approval rates on recommended services.\n\n14-day free trial: https://bayflow.com${linkedinCta}\n\n${signature}${canSpamFooter}`
  },
  {
    id: 'B',
    tone: 'social_proof',
    angle: 'outcome_focused',
    hook_type: 'statistic',
    subject: (biz) => `Re: ${biz} + 5 hours back per week`,
    body: (n, biz, c) => `Hi ${n},\n\nJust following up. Didn't want this to get buried.\n\n${teamSizeLine ? teamSizeLine + ', you know how fast admin piles up. ' : ''}The shops on BayFlow tell us the biggest win is getting rid of paper. Everything's digital, techs love it, customers love the photo inspections.\n\nWorth 2 minutes to check out: https://bayflow.com/demo${linkedinCta}\n\n${signature}${canSpamFooter}`
  },
  {
    id: 'C',
    tone: 'curiosity',
    angle: 'competitor_comparison',
    hook_type: 'competitor_weakness',
    subject: (biz) => `Re: Saw ${biz} online, had a thought`,
    body: (n, biz, c) => `Hi ${n},\n\nFollowing up on my note. ${techStackLine || ''}If you're currently on Mitchell 1 or a similar system, BayFlow might surprise you. It's a fraction of the cost and shops tell us it's easier to learn.\n\nHappy to answer any questions: https://bayflow.com${linkedinCta}\n\n${signature}${canSpamFooter}`
  },
  {
    id: 'D',
    tone: 'friendly',
    angle: 'compliment_first',
    hook_type: 'compliment',
    subject: (biz) => `Re: Nice reviews, ${biz}!`,
    body: (n, biz, c) => `Hey ${n},\n\nJust circling back. I know you're busy turning wrenches, so I'll keep it short.\n\nBayFlow = scheduling + digital inspections + invoicing + customer texting. $49/month. 14-day free trial.\n\nhttps://bayflow.com${linkedinCta}\n\n${signature}${canSpamFooter}`
  },
  {
    id: 'E',
    tone: 'urgent',
    angle: 'roi_focused',
    hook_type: 'roi',
    subject: (biz) => `Re: $49/month that pays for itself in week 1`,
    body: (n, biz, c) => `Hi ${n},\n\nFollowing up. One stat that might interest you: shops using digital inspections see approved repair dollars go up 20-30%. At $49/month, BayFlow is a no-brainer if you're not already using something.\n\nhttps://bayflow.com${linkedinCta}\n\n${signature}${canSpamFooter}`
  }
];

const followUp2Variants = [
  {
    id: 'A',
    tone: 'friendly',
    angle: 'breakup',
    hook_type: 'question',
    subject: (biz) => 'Should I close your file?',
    body: (n, biz, c) => `Hi ${n},\n\nI've reached out a couple times about BayFlow for ${biz}. I don't want to be annoying, so this is my last email.\n\nIf you're ever looking for shop management software built specifically for independent repair shops, we're at bayflow.com.\n\nGood luck with everything.\n\n${signature}${canSpamFooter}`
  },
  {
    id: 'B',
    tone: 'social_proof',
    angle: 'breakup',
    hook_type: 'statistic',
    subject: (biz) => 'Last note from me',
    body: (n, biz, c) => `Hi ${n},\n\nThis is my last email. Just wanted to leave you with this: 92% of shops that start a BayFlow trial stick with it.\n\nIf the timing's ever right, we're at bayflow.com. Wishing ${biz} the best.\n\n${signature}${canSpamFooter}`
  },
  {
    id: 'C',
    tone: 'curiosity',
    angle: 'breakup',
    hook_type: 'question',
    subject: (biz) => 'Closing the loop',
    body: (n, biz, c) => `Hi ${n},\n\nI'll take the hint. This is my last note about BayFlow for ${biz}.\n\nIf anything changes and you need a shop management tool that's simple, affordable, and built for independents, you know where to find us: bayflow.com\n\nAll the best.\n\n${signature}${canSpamFooter}`
  },
  {
    id: 'D',
    tone: 'friendly',
    angle: 'breakup',
    hook_type: 'compliment',
    subject: (biz) => 'Good luck out there',
    body: (n, biz, c) => `Hey ${n},\n\nLast email from me, promise. ${biz} clearly has a good thing going based on your reviews.\n\nIf you ever want to ditch the paperwork and go digital, BayFlow is at bayflow.com. $49/month, built for shops like yours.\n\nKeep up the great work.\n\n${signature}${canSpamFooter}`
  },
  {
    id: 'E',
    tone: 'urgent',
    angle: 'breakup',
    hook_type: 'roi',
    subject: (biz) => 'Final thought for ' + biz,
    body: (n, biz, c) => `Hi ${n},\n\nLast note. If ${biz} ever wants to save 5+ hours/week on admin and boost approved repair rates, BayFlow is here: bayflow.com\n\n$49/month, 14-day free trial. No pressure, no more emails from me.\n\nBest of luck.\n\n${signature}${canSpamFooter}`
  }
];

const variantSets = {
  initial: initialVariants,
  follow_up_1: followUp1Variants,
  follow_up_2: followUp2Variants
};

const variants = variantSets[emailType] || initialVariants;

// ── Variant Selection Logic ──
let selectedVariant = null;

if (perfData.length > 0) {
  const bestPerf = perfData[0];
  selectedVariant = variants.find(v => 
    v.tone === bestPerf.tone && v.angle === bestPerf.angle && v.hook_type === bestPerf.hook_type
  );
  if (!selectedVariant) {
    selectedVariant = variants.find(v => v.tone === bestPerf.tone && v.hook_type === bestPerf.hook_type);
  }
  if (!selectedVariant) {
    selectedVariant = variants.find(v => v.tone === bestPerf.tone);
  }
}

// If no learning data, use revenue/seniority to pick best angle
if (!selectedVariant && annual_revenue) {
  // High-revenue shops respond better to ROI messaging
  const rev = String(annual_revenue).replace(/[^0-9]/g, '');
  if (parseInt(rev) > 1000000) {
    selectedVariant = variants.find(v => v.tone === 'urgent' && v.hook_type === 'roi');
  }
}

if (!selectedVariant && seniority === 'owner') {
  // Owners respond to pain point / time-saving messaging
  selectedVariant = variants.find(v => v.tone === 'pain_point');
}

if (!selectedVariant) {
  const hashStr = lead.email || lead.id || '';
  let hash = 0;
  for (let i = 0; i < hashStr.length; i++) {
    hash = ((hash << 5) - hash) + hashStr.charCodeAt(i);
    hash = hash & hash;
  }
  const variantIndex = Math.abs(hash) % variants.length;
  selectedVariant = variants[variantIndex];
}

// ── Subject Line Override ──
let emailSubject = selectedVariant.subject(business_name);

if (subjectLineData.length > 0 && emailType === 'initial') {
  const bestSubject = subjectLineData[0];
  if (bestSubject.subject_line && bestSubject.positive_rate_pct && bestSubject.positive_rate_pct > 10) {
    emailSubject = bestSubject.subject_line
      .replace(/\{business_name\}/g, business_name)
      .replace(/\{first_name\}/g, name)
      .replace(/\{city\}/g, city);
  }
}

const emailText = selectedVariant.body(name, business_name, city || 'your area');

return [{
  json: {
    ...lead,
    emailSubject,
    emailText,
    selectedTone: selectedVariant.tone,
    selectedAngle: selectedVariant.angle,
    selectedHook: selectedVariant.hook_type,
    selectedVariantId: selectedVariant.id,
    learningDataUsed: perfData.length > 0,
    apolloDataUsed: !!(title || company_size || technologies || linkedin_url),
    learningContext: {
      perfDataCount: perfData.length,
      subjectLineCount: subjectLineData.length,
      recentLearningsCount: recentLearnings.length
    }
  }
}];

const emailData = $('Build Personalized Email').first().json;
const resendResponse = $input.first().json;
const sent = !!(resendResponse.id);

let newStatus = emailData.newStatus;

// If it was the initial email and it was sent, set to follow_up_1 (waiting for follow-up)
if (emailData.emailType === 'initial' && sent) {
  newStatus = 'follow_up_1';
} else if (emailData.emailType === 'follow_up_1' && sent) {
  newStatus = 'follow_up_2';
} else if (emailData.emailType === 'follow_up_2' && sent) {
  newStatus = 'completed';
}

return [{
  json: {
    id: emailData.id,
    email: emailData.email,
    emailType: emailData.emailType,
    emailSubject: emailData.emailSubject,
    emailText: emailData.emailText,
    newStatus: sent ? newStatus : emailData.status,
    sent,
    resendId: resendResponse.id || null,
    error: resendResponse.error || null,
    selectedTone: emailData.selectedTone,
    selectedAngle: emailData.selectedAngle,
    selectedHook: emailData.selectedHook,
    selectedVariantId: emailData.selectedVariantId,
    first_name: emailData.first_name,
    city: emailData.city,
    business_name: emailData.business_name
  }
}];

const payload = $input.first().json.body || $input.first().json;

// Parse inbound email webhook (Resend / generic format)
const fromEmail = payload.from || payload.sender || payload.envelope?.from || '';
const subject = payload.subject || '';
const body = payload.text || payload.plain || payload.html || '';
const replyDate = new Date().toISOString();

// Unsubscribe detection (CAN-SPAM compliance)
const unsubscribeKeywords = ['unsubscribe', 'remove me', 'stop emailing', 'opt out', 'opt-out', 'take me off', 'remove my email'];
const bodyLower = body.toLowerCase();
const subjectLower = subject.toLowerCase();
const isUnsubscribe = unsubscribeKeywords.some(kw => bodyLower.includes(kw) || subjectLower.includes(kw));

if (isUnsubscribe) {
  return [{
    json: {
      fromEmail: fromEmail.replace(/<|>/g, '').trim(),
      subject,
      body: body.substring(0, 2000),
      sentiment: 'unsubscribe',
      isUnsubscribe: true,
      replyDate
    }
  }];
}

// Standard sentiment detection for non-unsubscribe replies
const positiveKeywords = ['interested', 'yes', 'sure', 'tell me more', 'demo', 'try', 'sign up', 'pricing', 'sounds good', 'let\'s talk', 'schedule', 'call me'];
const negativeKeywords = ['not interested', 'no thanks', 'no thank', 'pass', 'not for us'];

let sentiment = 'neutral';

if (positiveKeywords.some(kw => bodyLower.includes(kw))) {
  sentiment = 'positive';
} else if (negativeKeywords.some(kw => bodyLower.includes(kw))) {
  sentiment = 'negative';
}

return [{
  json: {
    fromEmail: fromEmail.replace(/<|>/g, '').trim(),
    subject,
    body: body.substring(0, 2000),
    sentiment,
    isUnsubscribe: false,
    replyDate
  }
}];

const replyData = $('Parse Reply').first().json;
const fromEmail = replyData.fromEmail;
const sentiment = replyData.sentiment;
const replyDate = replyData.replyDate;
const replyPreview = (replyData.body || '').substring(0, 300);

// Determine outcome based on sentiment
let outcome = 'replied_neutral';
if (sentiment === 'positive') {
  outcome = 'replied_positive';
} else if (sentiment === 'negative') {
  outcome = 'replied_negative';
} else if (sentiment === 'unsubscribe') {
  outcome = 'unsubscribed';
}

// Calculate what_worked note for positive replies
let whatWorked = null;
if (sentiment === 'positive') {
  whatWorked = 'Lead responded positively. Reply preview: ' + replyPreview.substring(0, 100);
}

return [{
  json: {
    fromEmail,
    outcome,
    outcome_at: replyDate,
    notes: replyPreview,
    what_worked: whatWorked,
    sentiment
  }
}];
